10	use std::net::SocketAddr;
11	use std::sync::Arc;
12	use tokio::sync::RwLock;
13	use tokio::time::sleep;
14	
15	pub(crate) type SocketRef = Arc<UdtSocket>;
16	
17	static UDT_INSTANCE: OnceCell<RwLock<Udt>> = OnceCell::new();
18	pub(crate) static UDT_DEBUG: Lazy<bool> =
19	    Lazy::new(|| std::env::var("UDT_DEBUG").unwrap_or_default() != "");
20	
21	#[derive(Default, Debug)]
22	pub(crate) struct Udt {
23	    sockets: BTreeMap<SocketId, SocketRef>,
24	    multiplexers: BTreeMap<MultiplexerId, Arc<UdtMultiplexer>>,
25	    next_socket_id: SocketId,
26	    peers: BTreeMap<(SocketId, SeqNumber), BTreeSet<SocketId>>, // peer socket id -> local socket id
27	}
28	
29	impl Udt {
30	    fn new() -> Self {
31	        Self {
32	            next_socket_id: rand::random(),
33	            ..Default::default()
34	        }
35	    }
36	
37	    pub fn get() -> &'static RwLock<Self> {
38	        UDT_INSTANCE.get_or_init(|| {
39	            Udt::cleanup_worker();
40	            RwLock::new(Udt::new())
41	        })
42	    }
43	
44	    fn get_new_socket_id(&mut self) -> SocketId {
45	        let socket_id = self.next_socket_id;
46	        self.next_socket_id = self.next_socket_id.wrapping_sub(1);
47	        socket_id
48	    }
