50	    pub(crate) fn get_socket(&self, socket_id: SocketId) -> Option<SocketRef> {
51	        if let Some(socket) = self.sockets.get(&socket_id) {
52	            if socket.status() != UdtStatus::Closed {
53	                return Some(socket.clone());
54	            }
55	        }
56	        None
57	    }
58	
59	    pub(crate) async fn get_peer_socket(
60	        &self,
61	        peer: SocketAddr,
62	        socket_id: SocketId,
63	        initial_seq_number: SeqNumber,
64	    ) -> Option<SocketRef> {
65	        for socket in self
66	            .peers
67	            .get(&(socket_id, initial_seq_number))?
68	            .iter()
69	            .filter_map(|id| self.sockets.get(id))
70	        {
71	            if socket.peer_addr() == Some(peer) {
72	                return self.sockets.get(&socket.socket_id).cloned();
73	            }
74	        }
75	        None
76	    }
77	
78	    pub fn new_socket(
79	        &mut self,
80	        socket_type: SocketType,
81	        config: Option<UdtConfiguration>,
82	    ) -> Result<&SocketRef> {
83	        let socket = UdtSocket::new(self.get_new_socket_id(), socket_type, None, config);
84	        let socket_id = socket.socket_id;
85	        if let Entry::Vacant(e) = self.sockets.entry(socket_id) {
86	            return Ok(e.insert(Arc::new(socket)));
87	        }
88	        Err(Error::new(
89	            ErrorKind::AlreadyExists,
90	            "socket_id already exists",
91	        ))
92	    }
93	
94	    pub(crate) async fn new_connection(
95	        &mut self,
96	        listener_socket: &UdtSocket,
97	        peer: SocketAddr,
98	        hs: &HandShakeInfo,
99	    ) -> Result<()> {
100	        if let Some(existing_peer_socket) = self
101	            .get_peer_socket(peer, hs.socket_id, hs.initial_seq_number)
102	            .await
103	        {
104	            let socket = existing_peer_socket;
105	            if socket.status() == UdtStatus::Broken {
106	                // last connection from the "peer" address has been broken
107	                if *UDT_DEBUG {
108	                    eprintln!("Existing connection to peer {} is broken", peer);
109	                }
110	                listener_socket
111	                    .queued_sockets
112	                    .write()
113	                    .await
114	                    .remove(&socket.socket_id);
115	            } else {
116	                // Respond with existing socket configuration.
117	                let source_socket_id = hs.socket_id;
118	                let hs = {
119	                    let mut hs = hs.clone();
120	                    let configuration = socket.configuration.read().unwrap();
121	                    hs.initial_seq_number = socket.initial_seq_number;
122	                    hs.max_packet_size = configuration.mss;
123	                    hs.max_window_size = configuration.flight_flag_size;
124	                    hs.connection_type = -1;
125	                    hs.socket_id = socket.socket_id;
126	                    hs
127	                };
128	                let packet = UdtControlPacket::new_handshake(hs, source_socket_id);
129	                socket.send_to(&peer, packet.into()).await?;
130	                return Ok(());
131	            }
132	        }
133	
134	        let new_socket_id = self.get_new_socket_id();
135	
136	        let new_socket = {
137	            let multiplexer = listener_socket
138	                .multiplexer
139	                .read()
140	                .unwrap()
141	                .upgrade()
142	                .ok_or_else(|| Error::new(ErrorKind::Other, "Listener has no multiplexer"))?;
143	
144	            let config = listener_socket.configuration.read().unwrap().clone();
145	            if listener_socket.queued_sockets.read().await.len() >= config.accept_queue_size {
146	                return Err(Error::new(ErrorKind::Other, "Too many queued sockets"));
147	            }
148	
149	            let new_socket = UdtSocket::new(
150	                new_socket_id,
151	                hs.socket_type,
152	                Some(hs.initial_seq_number),
153	                Some(config),
154	            )
155	            .with_peer(peer, hs.socket_id)
156	            .with_listen_socket(listener_socket.socket_id, multiplexer);
157	            new_socket.open();
158	            new_socket
159	        };
160	
161	        let ns_id = new_socket.socket_id;
162	        let ns_isn = new_socket.initial_seq_number;
163	        let ns_peer_socket_id = hs.socket_id;
164	        let new_socket_ref = new_socket.connect_on_handshake(peer, hs.clone()).await?;
165	
166	        self.peers
167	            .entry((ns_peer_socket_id, ns_isn))
168	            .or_default()
169	            .insert(new_socket_ref.socket_id);
170	        self.sockets.insert(ns_id, new_socket_ref);
171	
172	        listener_socket.queued_sockets.write().await.insert(ns_id);
173	        listener_socket.accept_notify.notify_one();
174	        Ok(())
175	    }
176	
177	    pub async fn bind(&mut self, socket_id: SocketId, addr: SocketAddr) -> Result<()> {
178	        let socket = self
179	            .get_socket(socket_id)
180	            .ok_or_else(|| Error::new(ErrorKind::Other, "unknown socket id"))?;
181	
182	        if socket.status() != UdtStatus::Init {
183	            return Err(Error::new(ErrorKind::Other, "socket already binded"));
184	        }
185	
186	        self.update_mux(&socket, Some(addr)).await?;
187	        socket.open();
188	        Ok(())
189	    }
190	
191	    pub(crate) async fn update_mux(
192	        &mut self,
193	        socket: &UdtSocket,
194	        bind_addr: Option<SocketAddr>,
195	    ) -> Result<()> {
196	        if socket.configuration.read().unwrap().reuse_mux {
197	            if let Some(bind_addr) = bind_addr {
198	                let port = bind_addr.port();
199	                if port > 0 {
200	                    for mux in self.multiplexers.values() {
201	                        let socket_mss = socket.configuration.read().unwrap().mss;
202	                        if mux.reusable && mux.port == port && mux.mss == socket_mss {
203	                            socket.set_multiplexer(mux);
204	                            return Ok(());
205	                        }
206	                    }
207	                }
208	            }
209	        }
210	
211	        // A new multiplexer is needed
212	        let mux = {
213	            let configuration = socket.configuration.read().unwrap().clone();
214	            let (mux_id, mux) = if let Some(bind_addr) = bind_addr {
215	                UdtMultiplexer::bind(socket.socket_id, bind_addr, &configuration).await?
216	            } else {
217	                UdtMultiplexer::new(socket.socket_id, &configuration).await?
218	            };
219	            self.multiplexers.insert(mux_id, mux.clone());
220	            mux
221	        };
222	        socket.set_multiplexer(&mux);
223	        UdtMultiplexer::run(mux);
224	        Ok(())
225	    }
226	
227	    async fn garbage_collect_sockets(&mut self) {
228	        for (_, sock) in self
229	            .sockets
230	            .iter()
231	            .filter(|(_, s)| s.status() == UdtStatus::Broken)
232	        {
233	            if let Some(listen_socket_id) = sock.listen_socket {
234	                if let Some(listener) = self.sockets.get(&listen_socket_id) {
235	                    listener
236	                        .queued_sockets
237	                        .write()
238	                        .await
239	                        .remove(&sock.socket_id);
240	                }
241	            }
242	            tokio::spawn({
243	                let sock = sock.clone();
244	                async move { sock.close().await }
245	            });
246	        }
247	
248	        let to_remove: Vec<_> = self
249	            .sockets
250	            .iter()
251	            .filter(|(_, s)| s.status() == UdtStatus::Closing)
252	            .map(|(socket_id, _)| *socket_id)
253	            .collect();
254	        for socket_id in to_remove {
255	            if let Some(sock) = self.sockets.remove(&socket_id) {
256	                *sock.status.lock().unwrap() = UdtStatus::Closed;
257	            }
258	        }
259	    }
260	
261	    fn cleanup_worker() {
262	        tokio::spawn(async {
263	            let udt = Self::get();
264	            loop {
265	                udt.write().await.garbage_collect_sockets().await;
266	                sleep(std::time::Duration::from_secs(1)).await;
267	            }
268	        });
269	    }
270	}
