1	use crate::data_packet::{PacketPosition, UdtDataPacket, UdtDataPacketHeader};
2	use crate::seq_number::MsgNumber;
3	use crate::seq_number::SeqNumber;
4	use crate::socket::SocketId;
5	use bytes::Bytes;
6	use std::collections::VecDeque;
7	use tokio::io::{Error, ErrorKind, Result as IoResult};
8	use tokio::time::{Duration, Instant};
9	
10	const FETCH_BATCH_SIZE: usize = 100;
11	const DEFAULT_PAYLOAD_SIZE: usize = 1500;
12	
13	#[derive(Debug, Clone)]
14	pub(crate) struct SndBufferBlock {
15	    data: Bytes,
16	    msg_number: MsgNumber,
17	    origin_time: Instant,
18	    ttl: Option<u64>, // milliseconds,
19	    in_order: bool,
20	    position: PacketPosition,
21	}
22	
23	impl SndBufferBlock {
24	    fn has_expired(&self) -> bool {
25	        if let Some(ttl) = self.ttl {
26	            return self.origin_time.elapsed() > Duration::from_millis(ttl);
27	        }
28	        false
29	    }
30	
31	    fn as_data_packet(
32	        &self,
33	        seq_number: SeqNumber,
34	        dest_socket_id: SocketId,
35	        start_time: Instant,
36	    ) -> UdtDataPacket {
37	        UdtDataPacket {
38	            data: self.data.clone(),
39	            header: UdtDataPacketHeader {
40	                msg_number: self.msg_number,
41	                dest_socket_id,
42	                seq_number,
43	                in_order: self.in_order,
44	                position: self.position,
45	                timestamp: (start_time.elapsed().as_micros() & (u32::MAX as u128)) as u32,
46	            },
47	        }
48	    }
49	}
50	
51	#[derive(Debug)]
52	pub(crate) struct SndBuffer {
53	    max_size: u32,
54	    buffer: VecDeque<SndBufferBlock>,
55	    payload_size: usize,
56	    next_msg_number: MsgNumber,
57	    current_position: usize,
58	}
59	
60	impl SndBuffer {
61	    pub fn new(max_size: u32) -> Self {
62	        Self {
63	            max_size,
64	            buffer: VecDeque::new(),
65	            payload_size: DEFAULT_PAYLOAD_SIZE, // overwritten after connection
66	            next_msg_number: MsgNumber::zero(),
67	            current_position: 0,
68	        }
69	    }
70	
71	    pub fn add_message(&mut self, data: &[u8], ttl: Option<u64>, in_order: bool) -> IoResult<()> {
72	        let msg_number = self.next_msg_number;
73	        let now = Instant::now();
74	        let chunks = data.chunks(self.payload_size);
75	        let chunks_len = chunks.len();
76	
77	        if self.buffer.len() + chunks_len > self.max_size as usize {
78	            return Err(Error::new(ErrorKind::OutOfMemory, "Send buffer is full"));
79	        }
80	
81	        self.buffer
82	            .extend(chunks.enumerate().map(|(idx, chunk)| SndBufferBlock {
83	                data: Bytes::copy_from_slice(chunk),
84	                msg_number,
85	                origin_time: now,
86	                ttl,
87	                in_order,
88	                position: {
89	                    if idx == 0 && chunks_len == 1 {
90	                        PacketPosition::Only
91	                    } else if idx == 0 {
92	                        PacketPosition::First
93	                    } else if idx == chunks_len - 1 {
94	                        PacketPosition::Last
95	                    } else {
96	                        PacketPosition::Middle
97	                    }
98	                },
99	            }));
100	        self.next_msg_number = self.next_msg_number + 1;
101	        Ok(())
102	    }
103	
104	    pub fn ack_data(&mut self, offset: i32) {
105	        for _ in 0..offset {
106	            if self.buffer.pop_front().is_some() {
107	                self.current_position -= 1;
108	            }
109	        }
110	    }
111	
112	    pub fn read_data(
113	        &mut self,
114	        offset: usize,
115	        seq_number: SeqNumber,
116	        dest_socket_id: SocketId,
117	        start_time: Instant,
118	    ) -> Result<UdtDataPacket, (MsgNumber, usize)> {
119	        if let Some(block) = self.buffer.get(offset) {
120	            if block.has_expired() {
121	                // Move current_position to next message
122	                let mut pos = offset + 1;
123	                let mut msg_len = 1;
124	                while pos < self.buffer.len() {
125	                    if self.buffer[pos].msg_number == block.msg_number {
126	                        msg_len += 1;
127	                    } else {
128	                        break;
129	                    }
130	                    pos += 1;
131	                }
132	                if offset <= self.current_position && self.current_position < pos {
133	                    self.current_position = pos;
134	                }
135	                Err((block.msg_number, msg_len))
136	            } else {
137	                Ok(block.as_data_packet(seq_number, dest_socket_id, start_time))
